mapper.select:
SELECT id, username, password, position, remaining_vacation, is_admin
FROM vibe.users
WHERE id = #{id}

mapper.update:
UPDATE vibe.users
SET remaining_vacation = #{remainingVacation}
WHERE id = #{id}

UPDATE vibe.users
SET position = #{position,jdbcType=VARCHAR},
    remaining_vacation = #{remainingVacation,jdbcType=NUMERIC}
WHERE id = #{id}
